function toggleTheme(){const e=document.documentElement.classList.toggle("dark");localStorage.setItem("color-theme",e?"dark":"light"),changeGiscusTheme(e?"dark":"light")}document.querySelectorAll(".show-with-js").forEach(e=>{e.classList.remove("hidden")});function handleThemeIcons(){const e=document.getElementById("theme-toggle-dark-icon"),t=document.getElementById("theme-toggle-light-icon");document.documentElement.classList.contains("dark")?(e.classList.add("hidden"),t.classList.remove("hidden")):(t.classList.add("hidden"),e.classList.remove("hidden"))}function handleMobileMenu(){const e=document.querySelector('[aria-controls="mobile-menu"]'),t=document.getElementById("mobile-menu");if(!e||!t)return;e.addEventListener("click",()=>{const n=t.classList.toggle("hidden");e.setAttribute("aria-expanded",!n),e.classList.toggle("is-active")})}const btn=document.getElementById("scroll-to-top");window.onscroll=function(){document.body.scrollTop>300||document.documentElement.scrollTop>300?btn.classList.remove("hidden"):btn.classList.add("hidden")};function scrollToTop(){window.scrollTo({top:0,behavior:"smooth"})}const storedTheme=localStorage.getItem("color-theme");if(storedTheme)document.documentElement.classList.add(storedTheme),handleThemeIcons();else{const e=window.matchMedia("(prefers-color-scheme: dark)").matches?"dark":"light";localStorage.setItem("color-theme",e),document.documentElement.classList.add(e),handleThemeIcons()}function changeGiscusTheme(e){function t(e){const t=document.querySelector("iframe.giscus-frame");if(!t)return;t.contentWindow.postMessage({giscus:e},"https://giscus.app")}t({setConfig:{theme:e}})}const themeToggleBtn=document.getElementById("theme-toggle");themeToggleBtn.addEventListener("click",()=>{toggleTheme(),handleThemeIcons()}),handleMobileMenu()